def solve(vertices, edges):
    if not isinstance(vertices, list) or not all(isinstance(v, int) for v in vertices):
        raise ValueError("Vertices must be a list of integers.")

    if not isinstance(edges, list) or not all(isinstance(e, tuple) and len(e) == 2 for e in edges):
        raise ValueError("Edges must be a list of tuples with two integers each.")

    degree_count = {v: 0 for v in vertices}

    for u, v in edges:
        if u in degree_count:
            degree_count[u] += 1
        if v in degree_count:
            degree_count[v] += 1

    return degree_count
